import React, { Component } from 'react';
import styled from 'styled-components';
import { Card, CardBody, CardTitle, CardSubtitle, CardText, CardImg, Row, Col } from 'reactstrap';

const Banner = styled.div`
    position: relative;
    padding: 0em;
`;

const ProfileContainer = styled.div`
    text-align: center;
    width:600px;
`

const HiText = styled.h1`
    display: inline;
`
const InterludeText = styled.p`
    display: inline;
`

export class ProfileBanner extends Component {
    static displayName = ProfileBanner.name;

    constructor(props) {
        super(props);

        this.state = {
            priorScrollTop: null,
            initializedContent: <div/>
        }
    }


    render() {
        return (
            <Banner>
                <ProfileContainer> 
                    <HiText className='text-primary left-justified xl-font'>Hi<span className='text-bright'>! </span></HiText>
                    <InterludeText className='text-light left-justified m-font'>my name is</InterludeText>
                    <h1 className='text-bright xxl-font left-justified script-font'>Bradley</h1><h1 className='text-bright xxl-font left-justified script-font'>Mader<span className='text-primary left-justified sans-serif-font xxl-font'>.</span></h1>
                    <p className='text-light m-font left-justified'>I am a Software Engineer that focuses primarily on web technologies - Specifically as it relates to interconnected real-time experiences.</p>
                </ProfileContainer>
            </Banner>
        );
    }
}
